print(celsius_to_fahrenheit(20.0))"},{"conversion_notes":"The Python class is modeled as a Jac `node` because the object represents stateful domain data. Instance methods become node abilities written with `def`, and the entry block constructs a node instance and invokes its behavior directly.","jac_code":"node BankAccount {
    has owner: str;
    has balance: float = 0.0;

    def deposit(amount: float) -> float {
        self.balance += amount;
        return self.balance;
    }

    def withdraw(amount: float) -> bool {
        if amount <= self.balance {
            self.balance -= amount;
            return True;
        }
        return False;
    }
}

with entry {
    acct = BankAccount(owner="Mina", balance=50.0);
    acct.deposit(25.0);
    print(acct.withdraw(40.0));
    print(acct.balance);
}","python_code":"class BankAccount:
