for name in ["A", "B", "C"]:
    print(name)"},{"conversion_notes":"The Python recursive tree traversal is converted to Jac's walker/traversal style. Pages are nodes connected by `++>`, and the walker accumulates scores as it visits each `Page`, replacing explicit recursive calls with graph traversal behavior.","jac_code":"node Page {
    has title: str;
    has score: int;
}

walker ScoreCollector {
    has total: int = 0;

    can start with `root entry {
        visit [-->];
    }

    can collect with Page entry {
        self.total += here.score;
        visit [-->];
    }
}

with entry {
    home = Page(title="Home", score=2);
    docs = Page(title="Docs", score=5);
    api = Page(title="API", score=3);
    root() ++> home;
    home ++> docs;
    home ++> api;
    collector = ScoreCollector();
    collector spawn root();
    print(collector.total);
}","python_code":"class Page:
    def __init__(self, title, score):
        self.title = title
        self.score = score
        self.children = []

    def add_child(self, child):
        self.children.append(child)


def total_score(page):
    total = page.score
    for child in page.children:
        total += total_score(child)
    return total

home = Page("Home", 2)
docs = Page("Docs", 5)
api = Page("API", 3)
home.add_child(docs)
home.add_child(api)
print(total_score(home))"}]}
